   getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
     const opts = { ...(opOptions?.options || {}) };
     return opts;
   }
+
+  private getKeysetSort(orderBy: any): KeysetSort[] {
+    if (!orderBy) {
+      return [];
+    }
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    );
+    return entries.map(([field, direction]) => ({
+      field,
+      direction: normalizeKeysetDirection(direction),
+    }));
+  }
+
+  private addIdTieBreaker(keysetSort: KeysetSort[], findOptions: any) {
+    const idField = this.crudConfig.id_field;
+    if (keysetSort.some((sort) => sort.field === idField)) {
+      return;
+    }
+    keysetSort.push({ field: idField, direction: 'asc' });
+    findOptions.orderBy = [
+      ...(Array.isArray(findOptions.orderBy)
+        ? findOptions.orderBy
+        : [findOptions.orderBy]),
+      { [idField]: 'asc' },
+    ];
+  }
+
+  private decodeCursor(cursor: string, keysetSort: KeysetSort[]) {
+    let payload: Record<string, any>;
+    try {
+      payload = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('Invalid cursor');
+    }
+    if (!payload || Array.isArray(payload) || typeof payload !== 'object') {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    const expectedSort = keysetSort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+    for (const { field } of keysetSort) {
+      if (!Object.prototype.hasOwnProperty.call(payload, field)) {
+        throw new BadRequestException('Cursor is missing a sort field');
+      }
+    }
+    if (!Object.prototype.hasOwnProperty.call(payload, this.crudConfig.id_field)) {
+      throw new BadRequestException('Cursor is missing the entity ID');
+    }
+    return payload;
+  }
+
+  private makeKeysetQuery(
+    entity: Partial<T>,
+    cursor: Record<string, any>,
+    keysetSort: KeysetSort[],
+  ) {
+    const comparisons = keysetSort.map(({ field, direction }, index) => {
+      const preceding = keysetSort.slice(0, index).reduce(
+        (query, sort) => ({ ...query, [sort.field]: cursor[sort.field] }),
+        {},
+      );
+      return {
+        ...preceding,
+        [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] },
+      };
+    });
+    return { $and: [entity, { $or: comparisons }] };
+  }
+
+  private encodeCursor(entity: T, keysetSort: KeysetSort[]) {
+    const cursor = keysetSort.reduce(
+      (payload, { field }) => ({ ...payload, [field]: entity[field] }),
+      {} as Record<string, any>,
+    );
+    cursor.__sort = keysetSort
+      .map(({ field, direction }) => `${field}:${direction}`)
+      .join(',');
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
